use std::sync::{Arc, RwLock};

fn build_data() -> Arc<RwLock<Vec<i32>>> {
    Arc::new(RwLock::new(Vec::new()))
}

fn add_to_data(data: &RwLock<Vec<i32>>, value: i32) {
    let mut vec = data.write().unwrap();
    vec.push(value);
}

fn get_data(data: &RwLock<Vec<i32>>) -> Vec<i32> {
    // Reuses the vector reference instead of cloning it
    data.read().unwrap().clone()
